private struct YouTubeHomeScreen: View {
    var body: some View {
        NavigationStack {
            ZStack(alignment: .bottom) {
                ScrollView {
                    VStack(alignment: .leading, spacing: 20) {
                        YouTubeHeroBillboard()
                        ForEach(YouTubeDemoData.rows) { row in
                            YouTubePosterRow(title: row.title, items: row.items, accent: YouTubeTokens.ytRed)
                        }
                    }
                    .padding(.bottom, 24)
                }
                .background(YouTubeTokens.ytCanvasLight.ignoresSafeArea())
            }
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .principal) { Text("YouTube").font(.system(size: 20, weight: .bold)).foregroundStyle(YouTubeTokens.ytTextPrimaryLight) }
                ToolbarItem(placement: .topBarTrailing) { Image(systemName: "person.crop.circle").foregroundStyle(YouTubeTokens.ytTextPrimaryLight) }
            }
            .toolbarBackground(YouTubeTokens.ytCanvasLight, for: .navigationBar)
        }
    }
}

private struct YouTubeHeroBillboard: View {
