private struct YouTubeProfilePickerScreen: View {
    let profiles = YouTubeDemoData.profiles
    var body: some View {
        ZStack {
            YouTubeTokens.ytCanvasLight.ignoresSafeArea()
            VStack(spacing: 24) {
                Text("Qui regarde ?").font(.system(size: 32, weight: .bold)).foregroundStyle(YouTubeTokens.ytTextPrimaryLight)
                HStack(spacing: 20) {
                    ForEach(profiles) { p in
                        VStack(spacing: 8) {
                            RoundedRectangle(cornerRadius: 4).fill(p.color).frame(width: 84, height: 84)
                                .overlay(Text(p.emoji).font(.system(size: 36)))
                            Text(p.name).foregroundStyle(YouTubeTokens.ytTextSecondaryLight)
                        }
                    }
                    VStack(spacing: 8) {
                        RoundedRectangle(cornerRadius: 4).strokeBorder(YouTubeTokens.ytTextSecondaryLight, lineWidth: 1).frame(width: 84, height: 84)
                            .overlay(Image(systemName: "plus").font(.title).foregroundStyle(YouTubeTokens.ytTextSecondaryLight))
                        Text("Ajouter").foregroundStyle(YouTubeTokens.ytTextSecondaryLight)
                    }
                }
            }
        }
    }
}

